urlset:
{{ range .Data.Pages }}

  {{ .Permalink }}
  {{ if not .Lastmod.IsZero }}
  {{ .Lastmod.Format "2006-01-02T15:04:05Z07:00" | safeHTML }}
  {{ end }}
  {{ if .Sitemap.ChangeFreq }}
  {{ .Sitemap.ChangeFreq }}
  {{ end }}
  {{ if .Sitemap.Priority }}
  {{ .Sitemap.Priority }}
  {{ end }}

{{ end }}
